const allItems = $input.all();
const oldRaw = allItems[0]?.json || {};
const newRaw = allItems[1]?.json || {};
const oldBom = oldRaw.data || oldRaw;
const newBom = newRaw.data || newRaw;

// Basic info
const bomId       = newBom.bomId       || oldBom.bomId       || 'N/A';
const productName = newBom.productName || oldBom.productName || 'N/A';
const oldRevision = oldBom.revision    || 'N/A';
const newRevision = newBom.revision    || 'N/A';

// Parse componentsSummary into part-number sets
// Expected format from Extract: "PART-001: desc qty; PART-002: desc qty; ..."
// We extract part numbers (tokens that look like part numbers: contain dash + digits/letters)
function extractParts(summary) {
  if (!summary) return new Map();
  const parts = new Map();
  const lines = summary.split(/[\n;]+/).map(s => s.trim()).filter(Boolean);
  lines.forEach(line => {
    const tokens = line.split(/[\s:,|]+/);
    // Part number must: start with letters, contain a dash, have letters on both sides
    // e.g. MCU-STM32F4, CAP-0402-10U, IC-MPU6050, PCB-2LAYER
    // NOT: TYPE-C, 24-PIN, SOT-23-5, 6-AXIS, 2-LAYER (start with digit or too short)
    const partNum = tokens.find(t =>
      t.length >= 8 &&  // real part numbers are usually 8+ chars
      /^[A-Z]{2,}[-][A-Z0-9]{2,}/i.test(t) &&  // 2+ letters, dash, 2+ chars
      !/^(EA|PCS|KG|SMD|REV|BOM|SOT|SMT|DIP|QFP|LITE|TYPE|SIDE|WIRE)[-]/i.test(t)
    );
    if (partNum) {
      // Qty: number followed by EA/PCS or just standalone number after part desc
      const qtyMatch = line.match(/(\d+)\s*(?:EA|PCS|each)/i) ||
                       line.match(/Qty[:\s]+(\d+)/i) ||
                       line.match(/,\s*(\d{1,4})\s*,/);
      const qty = qtyMatch ? parseInt(qtyMatch[1]) : 1;
      parts.set(partNum.toUpperCase(), { line: line.trim(), qty });
    }
  });
  return parts;
}

const oldParts = extractParts(oldBom.componentsSummary);
const newParts = extractParts(newBom.componentsSummary);

// Find added, removed, changed
const addedList   = [];
const removedList = [];
const changedList = [];

// Check for removed or changed
oldParts.forEach((oldVal, partNum) => {
  if (!newParts.has(partNum)) {
    removedList.push(partNum);
  } else {
    const newVal = newParts.get(partNum);
    if (oldVal.qty !== newVal.qty) {
      changedList.push(`${partNum}: qty ${oldVal.qty}→${newVal.qty}`);
    }
  }
});

// Check for added
newParts.forEach((newVal, partNum) => {
  if (!oldParts.has(partNum)) {
    addedList.push(partNum);
  }
});

// Fallback to count-based if part parsing yielded nothing
const oldCount = parseInt(oldBom.totalComponents) || 0;
const newCount = parseInt(newBom.totalComponents) || 0;

let added   = addedList.length;
let removed = removedList.length;
let specQtyChanges = changedList.length;

// If parsing found nothing, fall back to count diff
if (added === 0 && removed === 0 && oldCount !== newCount) {
  const diff = newCount - oldCount;
  added   = diff > 0 ? diff : 0;
  removed = diff < 0 ? Math.abs(diff) : 0;
}

const totalChanges = added + removed + specQtyChanges;

const changeParts = [
  added   > 0 ? `${added} added (${addedList.join(', ') || 'see BOM'})`           : '',
  removed > 0 ? `${removed} removed (${removedList.join(', ') || 'see BOM'})`     : '',
  specQtyChanges > 0 ? `${specQtyChanges} qty/spec changes (${changedList.join(', ')})` : ''
].filter(Boolean);

const changeSummary = changeParts.join('; ') || 'No changes detected';

return [{ json: {
  bomId, productName,
  productNumber:   newBom.productNumber   || oldBom.productNumber   || 'N/A',
  oldRevision,     newRevision,
  oldRevisionDate: oldBom.revisionDate    || 'N/A',
  newRevisionDate: newBom.revisionDate    || 'N/A',
  oldComponents:   oldCount,
  newComponents:   newCount,
  componentsAdded:   added,
  componentsRemoved: removed,
  addedPartNumbers:  addedList.join(', ')   || 'None',
  removedPartNumbers:removedList.join(', ') || 'None',
  specChanges:       specQtyChanges,
  specChangeDetails: changedList.join('; ') || 'None',
  totalChanges,
  changeSummary,
  preparedBy:     newBom.preparedBy     || 'N/A',
  approvedBy:     newBom.approvedBy     || 'N/A',
  effectivityDate:newBom.effectivityDate|| 'N/A',
  processedAt: new Date().toISOString()
}}];

